.darma-loader-darma-custom-007 {
  width: 50px;
  aspect-ratio: 1.154;
  clip-path: polygon(50% 0, 100% 100%, 0 100%);
  display: grid;
  background: var(--loader-color, #3A89C9);
}
.darma-loader-darma-custom-007::before,
.darma-loader-darma-custom-007::after {
  content: "";
  grid-area: 1/1;
  background: inherit;
  clip-path: inherit;
  transform-origin: 50% 66%;
  animation: darma-loader-darma-custom-007-l7-1 2s infinite;
}
.darma-loader-darma-custom-007::before {
  background: var(--loader-secondary-color, #9CC4E4);
  animation: darma-loader-darma-custom-007-l7-2 2s infinite 1s;
}
@keyframes darma-loader-darma-custom-007-l7-1 {
  0%, 99.9% { transform: scale(1); }
  50%, 99% { transform: scale(0); }
}
@keyframes darma-loader-darma-custom-007-l7-2 {
  0%, 51% { transform: scale(1); }
  50% { transform: scale(0); }
}

